file.content:
  gap: var(--space-2xl);
  flex: 1;
  min-height: 0;
}

/* Git log column - time markers only */
.timeline-log {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  min-width: 200px;
}

.timeline-log__header {
  font-family: var(--font-mono);
  font-size: 1.1rem;
  margin-bottom: var(--space-md);
  color: var(--terminal-white-muted);
}

.timeline-log__prompt {
  color: var(--terminal-green);
  font-weight: bold;
  text-shadow: var(--glow-text-green);
  margin-right: var(--space-sm);
}

.timeline-log__list {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.timeline-log__item {
  padding: var(--space-sm) var(--space-md);
  border-left: 3px solid var(--terminal-border);
  transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  opacity: 0.5;
}

.timeline-log__item--past {
  opacity: 0.35;
}

.timeline-log__item--active {
  opacity: 1;
  border-left-color: var(--terminal-orange);
  background: linear-gradient(90deg, rgba(240, 136, 62, 0.12) 0%, transparent 100%);
}

.timeline-log__item--emphasis.timeline-log__item--active {
  border-left-color: var(--terminal-green);
  background: linear-gradient(90deg, rgba(126, 231, 135, 0.12) 0%, transparent 100%);
}

.timeline-log__time {
  font-family: var(--font-mono);
  font-size: var(--slide-text-body);
  font-weight: 700;
  color: var(--terminal-orange);
  transition: all 0.3s ease;
  white-space: nowrap;
}

.timeline-log__item--active .timeline-log__time {
  text-shadow: var(--glow-text-orange);
}

.timeline-log__time--emphasis {
  color: var(--terminal-green);
}

.timeline-log__item--active .timeline-log__time--emphasis {
  text-shadow: var(--glow-text-green);
}

/* Hint box in left column - compact tooltip style */
.timeline-hint-box {
  margin-top: auto;
  align-self: flex-start;
  background: var(--terminal-bg-elevated);
  border: 1px solid var(--terminal-border);
  border-radius: var(--input-border-radius);
  padding: var(--space-sm) var(--space-md);
}

.timeline-hint-box__header {
  display: flex;
  align-items: center;
  gap: var(--space-sm);

