.timeline-panel__image--zoom-anim {
  /* Pin the pre-zoom size in stage pixels so the final crop is deterministic.
     Source is 1060x1382 (aspect ~0.767); 500px wide → ~651px tall. */
  width: 500px;
  max-width: 500px;
  height: auto;
  max-height: none;
  transform-origin: top center;
  object-position: top center;
  animation: timeline-zoom-to-top 2s cubic-bezier(0.4, 0, 0.2, 1) 0.6s forwards;
}

@keyframes timeline-zoom-to-top {
  /* End scale = (panel-width ~1500px with safety margin) / 500px. 2.6 keeps
     horizontal content inside the panel on every screen because both the
     image and the panel live on the fixed 1920x1080 stage. */
  0%   { transform: scale(1); }
  100% { transform: scale(2.6); }
}

